var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"……오셨군요, 스승님.","JPN":"……いらっしゃったんですね、師匠。","ENG":"So you're finally here, Master.","TWN":"……師父來啦。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"미안하군. 서두른다고 했는데…… 아무래도 늦어버린 것 같아.","JPN":"すまない。急いだつもりだったが……どうやら間に合わなかったようだ。","ENG":"Sorry. I tried to hurry… but I fear it's too late.","TWN":"抱歉，說會趕到……結果還是晚了一步。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"괜찮습니다. 스승님 탓이 아니에요.","JPN":"大丈夫です、師匠のせいではありません。","ENG":"It's okay. It's not your fault.","TWN":"沒關係，不是師父的錯。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"조금은 더 견딜 줄 알았는데…… 광증의 진행이 갑자기 빨라졌어요.","JPN":"もう少し耐えられると思いましたが……狂症の進行が急に早まりました。","ENG":"I thought I could hold out a bit longer… but the madness is accelerating.","TWN":"我以為我還能再撐一下……但狂氣的作用突然加速。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"혹시…… 시윤이는 무사합니까?","JPN":"あの……シリュウは無事ですか？","ENG":"Is… Shiyoon all right?","TWN":"我們時雲……他沒事吧？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"쓰러지기 전에 뒷모습을 본 것 같은데……. 확실하지가 않아요.","JPN":"倒れる前に後ろ姿を見たような気がしますが……確信できなくて。","ENG":"I thought I saw his back before I fell… But I'm not so sure.","TWN":"我倒下前好像有看到他的背影……但又不太確定。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그 아이라면 창고에 잠시 눕혀 뒀다.","JPN":"……あの子なら倉庫に寝かせておいた。","ENG":"…The kid's lying in the warehouse.","TWN":"……我先把他安置在倉庫裡。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"피를 많이 흘리긴 했지만, 목숨은 건졌어.","JPN":"かなり出血していたようだが、一命をとりとめた。","ENG":"He lost a lot of blood, but he'll make it.","TWN":"雖然流了不少血，但撿回了一條小命。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그렇군요…… 다행입니다.","JPN":"そうだったんですね……よかったです。","ENG":"I see… Thank goodness.","TWN":"原來如此……那就好。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭔가…… 남길 말은 없나?","JPN":"なにか……言い残すことはないか？","ENG":"Any last words?","TWN":"你……有什麼要交代的嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"연화는…… 그 고통을 견디면서도…… 최선을 다했습니다.","JPN":"レンカは……その苦痛に耐えながらも……最善を尽くしました。","ENG":"Yeonhwa tried her best… even as she withstood all that pain…","TWN":"蓮華她…已經盡力………忍受那個痛苦了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"하지만 운명이란…… 번뇌란 참으로 끊어내기 어렵군요.","JPN":"しかし運命とは……煩悩というのは本当に断ち切れないものですね。","ENG":"But our fate… Kleshas seem to be impossibly insurmountable.","TWN":"只是……終究無法擺脫命運和煩惱。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그러니…… 마지막만큼은 고통 없이……","JPN":"だから……最期だけは苦しませずに……","ENG":"So please… When you put her down…","TWN":"我希望……她最後可以沒有痛苦地……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그녀를…… 연화를 보내 주십시오……","JPN":"彼女を……レンカを眠らせてください……","ENG":"Please make it painless for Yeonhwa…","TWN":"離……開……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……알겠다.","JPN":"……わかった。","ENG":"...Very well.","TWN":"……我知道了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"약속해 주세요, 스승님. 그 아이를 보살펴 주겠다고.","JPN":"約束してください、師匠。あの子の面倒を見てくれると。","ENG":"Promise me, Master. Promise me that you'll take care of him.","TWN":"師父，答應我你會好好照顧他，"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그 아이가 저처럼 되지 않게……. 진실에서 멀어지게 해 주겠다고요.","JPN":"あの子が私と同じ道を歩まないように……真実から遠ざけてあげてください。","ENG":"Don't let him become like me… Please keep him as far away from the truth as possible.","TWN":"不要讓他變得像我一樣……永遠不要讓他知道真相。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그래, 그 정도라면.","JPN":"……それぐらいならいいだろう。","ENG":"…I will, if that's all you ask.","TWN":"……好，如果是這樣…"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"약속하지.","JPN":"約束する。","ENG":"I promise.","TWN":"我答應你。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"고마워요…….","JPN":"……ありがとうございます。","ENG":"Thank you…","TWN":"謝謝你……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그럼 이제…… 저도 가야 할 시간이네요. 그이가 기다리고 있어요.","JPN":"それでは……そろそろ私も逝かなければ。あの人が待っています。","ENG":"Then… I suppose it's time for me to go now. He's waiting for me.","TWN":"那麼……我也該離開了，他在等我。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"남길 말…… 아니, 전할 말은 없나?","JPN":"残したい言葉……いや、伝えたい言葉はないか？","ENG":"Any last words… I mean, anything you want to say to the kid?","TWN":"你有遺言……不，你有什麼話想對他說嗎？"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"아시잖아요, 스승님. 전 그 아이에게 유언을 남길 수 없어요.","JPN":"ご存知でしょう、師匠。私はあの子に遺言を遺すことはできません。","ENG":"You know how it is, Master. I can't leave any words for that child.","TWN":"師父你也知道，我不能對那孩子留下遺言。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"이미 용혈의 광기에 사로잡힌 이상…… 또다시 이성을 잃겠죠.","JPN":"すでに龍血の狂気に囚われている以上……また理性を失ってしまうでしょう。","ENG":"Now that the Dragon Blood's madness has taken me… I will lose myself yet again.","TWN":"龍血的狂氣已經滲入我的思想……我會再次失去理智的。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"저와 접촉하게 되면 시윤이도 광기의 발현이 시작될 거예요.","JPN":"私と接触すると、シリュウも狂気の発現が始まります。","ENG":"If I get in touch with Shiyoon, it will trigger the child's madness too.","TWN":"和時雲接觸的話，他就會開始發現狂氣的存在。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그러니까…… 시윤이 대신 스승님이 들어 주세요.","JPN":"だから……シリュウの代わりに師匠が聞いてください。","ENG":"So instead of Shiyoon… Please hear these words on his behalf, Master.","TWN":"所以……我想對時雲說的話，就只能說給師父聽。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"한없이 괴롭고, 한없이 고통스러운 삶이었지만…….","JPN":"限りなく辛く、そして苦しい人生だったけど……","ENG":"Although my life was full of suffering and agony…","TWN":"雖然我這一生在無盡的痛苦和折磨中度過……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"네가 있어 줘서……. 내가 인간이었다는 사실을 잊지 않을 수 있었다고.","JPN":"シリュウ、あなたがいてくれて……私が人間であったという事実を忘れずにいられた、と。","ENG":"It was all thanks to you… that I could hold onto my humanity.","TWN":"但因為有你……讓我忘不掉我曾經身為人的事實。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"정말 고마웠고…… 행복했다고.","JPN":"本当にありがとう……幸せだった、と。","ENG":"Thank you my child… My joy…","TWN":"謝謝你……因為你我很幸福。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네 마지막 말, 확실하게 들었다.","JPN":"お前の最期の言葉、確かに受け取った。","ENG":"I heard your last words, loud and clear.","TWN":"最後那一句，我聽得很清楚。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 덤벼라. 연화.","JPN":"では、かかってこい、レンカ。","ENG":"Now, come at me. Yeonhwa.","TWN":"那就來吧，蓮華，"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 번뇌에 사로잡힌 마룡이여.","JPN":"いや、煩悩に囚われた魔龍よ。","ENG":"Or rather… the Demon Dragon swept up in Kleshas.","TWN":"不，是陷入煩惱的魔龍！"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"한때는 네 스승이었던 자로서……","JPN":"かつてお前の師匠だった者として……","ENG":"As your former Master…","TWN":"就由這個曾經身為師父的我……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"최선을 다해 고통 없이, 단숨에 끝내 주겠다.","JPN":"最善を尽くし、苦痛なく一息で終わらせてやる。","ENG":"I'll try my best to make it quick and painless.","TWN":"我會盡量讓你不感受到痛苦的。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 처음부터 다 알고 있었던 거로군.","JPN":"君は最初から知っていたんだな。","ENG":"So you knew everything all along.","TWN":"原來你從一開始就全都知道了。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 창고에서 눈을 맞으며…… 힐데 소대장과 부모님의 대화를 들었겠지.","JPN":"雪が舞うあの倉庫で…… ヒルデ小隊長とご両親の会話を聞いただろう。","ENG":"In that snowy warehouse… You must have heard Hilde speak with your parents.","TWN":"那個下雪天，希爾德和你父母親的對話……你在倉庫裡都聽見了吧？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 귀가 아주 밝은 편이었으니까.","JPN":"君は耳がとても良い方だからな。","ENG":"You've got very good hearing, after all.","TWN":"因為你的耳朵很敏銳。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"누구죠, 당신은?","JPN":"あなたは、誰ですか？","ENG":"Who are you?","TWN":"請問你是誰？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"목소리가 익숙한데…… 절 아시나요?","JPN":"聞き覚えのある声ですが……僕のことを知っているのですか？","ENG":"Your voice sounds familiar… Do you know me?","TWN":"聲音好耳熟……我們認識嗎？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오랜 시간을 살다 보니, 나에겐 많은 이름들이 있다네.","JPN":"長い時間を生きているせいか、私には多くの名前があってね。","ENG":"I've been around long enough to be known by many names.","TWN":"我目前已經累積很多名字欸？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자, 사장, 그리고 때로는…… 현자라고 불리기도 했지.","JPN":"管理者、社長、時には……賢者と呼ばれていた時もあった。","ENG":"Administrator, Boss, and at one point… the Sage.","TWN":"什麼管理者啦，老闆啦，有時候人家還會叫我…… 智者呢！"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……당신이?","JPN":"あなたが……？","ENG":"…That was you?","TWN":"……你說你？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요. 그 로봇 뒤에 누군가 계실 줄은 알았지만……","JPN":"そうだったんですね。あのロボットの裏に誰かが存在することは知っていましたが……","ENG":"I see. I had a feeling someone would be behind that robot…","TWN":"原來如此，我是有猜想過那個機器人裡面應該有某個人……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"직접 보니 납득이 되네요.","JPN":"直接この目で見れば、納得がいきますね。","ENG":"But now that I've met you in person, it all makes sense.","TWN":"現在親眼見到後，我猜的應該沒錯！"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 여긴 어디죠? 전 분명 죽었을 텐데요?","JPN":"それで、ここはどこですか？　僕は確かに死んだはずですが。","ENG":"So where am I? I thought I was dead.","TWN":"不過這裡是哪裡？我不是已經死了嗎？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 여긴 삶과 죽음의 경계 같은 곳이지.","JPN":"そうだ。ここは生と死の境界のような場所だ。","ENG":"You're right. This is sort of like the boundary between life and death.","TWN":"沒錯，這裡彷彿就像是生與死的交界。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"용혈의 후계자들이 마지막으로 시험 받는 곳이기도 하고.","JPN":"龍血の後継者たちが最後の試練を受ける場所でもある。","ENG":"It's also where the heirs of Dragon Blood are given their final test.","TWN":"龍血的後裔會在這裡接受最後的考驗。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"시험……?","JPN":"試練……？","ENG":"A test…?","TWN":"考驗……？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>용</color>이 되기 위한 마지막 시험이지.","JPN":"<color=#ffd34c>龍</color>になるための、最後の試練だ。","ENG":"The final test to become a <color=#ffd34c>Dragon</color>.","TWN":"就是成為<color=#ffd34c>龍</color>的最後一個考驗。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원래라면 자네는 이 곳에서 자네의 선조들이 쌓아 온 번뇌들과 마주했어야 하네.","JPN":"本来なら君はここで君の先祖たちが築いてきた煩悩と向き合うべきだった。","ENG":"Normally, this is where you'd come to face the Kleshas your ancestors have accumulated.","TWN":"原本你應該在這裡面對你祖先們累積至今的煩惱。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"누대에 걸쳐 쌓여 왔던 망설임과 원한, 후회와 탐욕, 분노와 교만, 불신…….","JPN":"累代にわたり積み重なった逡巡と怨念、後悔と貪欲、怒りと傲慢、不信……","ENG":"All the hesitations, grudges, regrets, greed, rage, arrogance, and incredulity built up over generations…","TWN":"像是躊躇、怨恨、貪念、驕傲和懷疑……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 모든 번뇌를 끊어낼 수 있다면 진정한 용으로 다시 태어나겠지만.","JPN":"そのすべての煩悩を断ち切ることができれば、真なる龍へと生まれ変わるだろう。","ENG":"If you can overcome all those Kleshas, you'll be reborn as a true Dragon.","TWN":"只要能斷開這些煩惱就能成為真正的龍。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러지 못한다면 자네 또한 자아를 잃은 채 용혈의 망령이 되어 또다른 번뇌를 쌓게 되겠지.","JPN":"それができなければ、\\n君もまた自我を失った龍血の亡霊となり、\\nさらに煩悩を一つ重ねることになるだろう。","ENG":"Otherwise, you'll become another lost soul of Dragon Blood to add to the pile of Kleshas.","TWN":"失敗的話，你也會失去自我成為龍血的亡靈，再繼續累積其他煩惱。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이상하군.","JPN":"しかしおかしいな。","ENG":"But it's strange.","TWN":"但奇怪的是…"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 이곳에서 어떤 번뇌도 고통도 느끼고 있는 것 같지 않아.","JPN":"君はここで煩悩も苦痛も感じているようには見えないな。","ENG":"You don't seem to feel anything Kleshas or pain here.","TWN":"為什麼你好像沒有感受到任何煩惱或是痛苦？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 여기 오기 전에도 용혈의 광기에 침식되지 않았지.","JPN":"いや、ここ来る前から龍血と狂気に侵食されていなかった。","ENG":"In fact, you didn't even succumb to madness before you got here.","TWN":"而且在你來到這裡之前，不是已經受到龍血狂氣的侵蝕嗎？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"분명, 용혈의 정보 오염에 노출되어 있었으면서도 말이야.","JPN":"確か、龍血の情報汚染を受けていたにも関わらず。","ENG":"Even when you were clearly exposed to the Dragon Blood that causes contamination of mind.","TWN":"你明明就有暴露在龍血的污染中。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 그게 가능했지?","JPN":"どうしてなんだ？","ENG":"How did you pull that off?","TWN":"為什麼你好像一副沒事的樣子？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설마 그 구도자도 해내지 못했던, 번뇌를 극복하는 데 성공한 건가?","JPN":"まさかあの求道者も果たせなかった、煩悩の克服に成功したのか？","ENG":"Did you manage to overcome Kleshas? That's a feat that even the Seeker could not accomplish.","TWN":"難道你克服了連求道者也勝不過的煩惱？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……모르겠군요.","JPN":"……わかりません。","ENG":"…I’m not sure.","TWN":"我不知道……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 아직도 그 번뇌라든가 용이라든가 하는 것이 뭔지 이해하지 못하겠어요.","JPN":"僕はまだ煩悩や龍が何なのか理解できません。","ENG":"I still don't get what all this stuff about Kleshas or Dragons mean.","TWN":"我連什麼煩惱，什麼龍的都還搞不清楚。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그저…… 제 자신으로 살고 싶었을 뿐입니다.","JPN":"僕はただ……自分自身で生きたかっただけです。","ENG":"All I wanted… was just to be me.","TWN":"我……只是想做我自己。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 성녀라는 분이 말하더군요.","JPN":"あの聖女という方が言っていました。","ENG":"That so-called Saintess told me.","TWN":"那個叫聖女的有說過，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"삶은 복수라고, 살아간다는 것은 나 이외의 타인에게 복수하는 것이라고.","JPN":"人生は復讐で、生きていくということは僕以外の誰かに復讐をすることだと。","ENG":"She said life is vengeance, and that to go on living means to take vengeance on someone other than myself.","TWN":"報仇是要以其他人為對象而不是自己。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래요. 그것도 삶을 살아가는 하나의 방법이겠죠.","JPN":"そうですね。それも一つの生き方でしょう。","ENG":"I mean, sure. That's probably one way to live.","TWN":"沒錯，那麼做確實是報仇，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그렇게 타인에게 투영된 자신의 모습만을 쫓다 보면…….","JPN":"しかし、そうやって他人に投影された自分の姿ばかり追いかけていては……","ENG":"But if you go on chasing after the projection of your image that other people see…","TWN":"但若是焦點只放在怎麼向其他人報仇……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"사람은 어느 순간 전혀 다른 존재가 되어 버려요.","JPN":"人はある瞬間に全く別の存在になってしまいます。","ENG":"You'll find yourself becoming someone else entirely one day.","TWN":"久而久之，自己就會在某個瞬間完全失去自我。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그렇게 되고 싶지 않았어요.","JPN":"僕はそうなりたくありません。","ENG":"I don't want that for myself.","TWN":"而我，不想變成那樣。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그래서 미나 양을 쏘지 않은 건가?","JPN":"……だからミナ君を撃たなかったのか？","ENG":"…Is that why you didn't shoot Mina?","TWN":"……所以你沒有朝米娜開槍嗎？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로 인해 번뇌와, 고통과, 후회를 얻고……. 심지어 목숨까지 잃게 된다고 하더라도?","JPN":"それによって煩悩や苦痛、後悔を得て……さらに命まで失うとしても？","ENG":"Even if that would bring you all that Kleshas, suffering, and regret… And even cost you your life?","TWN":"因為這樣而得到煩惱、痛苦、後悔……甚至失去性命也無所謂嗎？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……예전에 미나 양에게 했던 말이 있죠.","JPN":"……以前ミナさんに言ったんです。","ENG":"…I once told Mina something.","TWN":"……米娜之前說過，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자신을 잃어 버릴지도 모르는 결정과 마주했을 때는…… 결코 양보하지 말라고.","JPN":"自分を失ってしまうかもしれない決断と向き合った時は……決して譲るな、と。","ENG":"I told her that she should never back down when she's met with a choice that could make her forfeit her true self.","TWN":"面對到可能會失去自我的決定時……她是絕對不會退讓的。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 겪은 비극도, 고통도, 후회도 모두 제 일부입니다.","JPN":"僕が経験した悲劇も、苦痛も、後悔も、すべて僕の一部です。","ENG":"All the tragedy, suffering, and regret I've experienced are a part of me as well.","TWN":"我所經歷到的悲劇、痛苦、後悔，都是我生命的一部分。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그로 인해 저는 부모님이 절 사랑한다는 걸 알 수 있었고……","JPN":"その結果、僕は両親に愛されていたことを知れましたし……","ENG":"Because of that, I knew how much my parents loved me…","TWN":"因為這樣，我可以知道我的父母親是愛我的……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"누구보다 강하지만 살아가는 것은 서툴기만 한 스승님을 만나게 되었고……","JPN":"誰よりも強いけれど、生きることがとても下手な師匠に出会えて……","ENG":"And I met my Master, who is stronger than anyone, but clumsy at life…","TWN":"因為這樣，我才可以遇到能力很好實際上卻是個生活白癡的師父……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 세상을 구하는 모습도 볼 수 있었어요.","JPN":"ミナさんがこの世界を救う姿も見れました。","ENG":"And I even got to watch Mina save the world.","TWN":"因為這樣，我才能看到米娜拯救世界的英姿。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래요. 누군가는 그걸 번뇌라고 부를 수도 있겠죠.","JPN":"そうですね。誰かはそれを煩悩と呼ぶこともあるでしょう。","ENG":"Sure. Some might call that Kleshas or suffering.","TWN":"沒錯，有些人可能會將這些視為煩惱，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 설령 영원히 용이 되는 길을 포기하고 뱀으로 땅을 기게 되더라도…….","JPN":"しかし、たとえ永遠に龍になる道を諦めて、蛇となり地面を這うことになっても……","ENG":"But even if I must forfeit becoming a Dragon and remain as a snake that crawls the earth on its belly…","TWN":"但就算無法成為一尾活龍，只能在地上做一條魯蛇……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저는 번뇌를 버리지 않겠어요.","JPN":"僕は煩悩を捨てません。","ENG":"I will not renounce my Kleshas.","TWN":"我也不會扔掉煩惱。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그것이…… 제가 살아가는 방법이니까요.","JPN":"それが……僕の生き方ですから。","ENG":"Because… that is the way I choose to live.","TWN":"因為這就是……我的生存之道。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 멍청이가! 대체 무슨 짓을 한 건가?!","JPN":"この馬鹿が！　いったい何をしたんだ！？","ENG":"You fool! What have you done?!","TWN":"你這個笨蛋！你到底做了什麼？！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"용혈이라는 건 결국 변종 클리포트 인자에 불과해.","JPN":"龍血なんて、結局は変種のクリフォト・ファクターにすぎない。","ENG":"Dragon Blood is nothing but a variant Qliphoth Factor.","TWN":"所謂的龍血不過就是變種卡巴拉因子！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 많은 양을 주입하면 클리포트 인자가 네 운명과 결합되고 말아!","JPN":"そんなに大量を注入すればクリフォト・ファクターが君の運命と結びついてしまう！","ENG":"If you inject that much, the Qliphoth Factor will bond with your fate!","TWN":"注入這麼大的量，卡巴拉因子會和你的命運連結在一起的！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무슨 소린지 모르겠나? 더는 인간이 아니게 된다고!","JPN":"どうなるかわからないのか！？　もう人間ではなくなるんだぞ！","ENG":"Don't you see what that means? You won't be human anymore!","TWN":"你懂我的意思嗎？意思就是你會變得人不像人！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죽어서도 구원받지 못해! 영원히 고통 받는단 말이야!","JPN":"死んでも救われない！　永遠に苦しむ羽目になる！","ENG":"You'll never find redemption, even in death! You'll suffer for all eternity!","TWN":"就算死也無法得到救贖！永遠受到痛苦的折磨！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"……알고 있어요.","JPN":"……わかっています。","ENG":"…I'm aware.","TWN":"我知道……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"하지만 이 방법밖에는 없었으니까요.","JPN":"しかし、この方法しかありません。","ENG":"But this is the only way.","TWN":"但除此之外別無他法！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 무슨……!","JPN":"それはどういう……！","ENG":"Don't be ridiculous!","TWN":"你在說什麼……！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"당신이 거쳐 온 무수한 세계들과 달리……. 이 세계는 아직 준비되지 못했어요.","JPN":"あなたが経てきた無数の世界と違い……この世界はまだ準備ができていませんでした。","ENG":"Unlike the countless worlds you've journeyed through… This world isn't ready yet.","TWN":"這個世界和你之前經歷過的無數個世界不同……這個世界還沒準備好，"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"그래서 자신을 지킬 대적자조차도 제대로 만들어내지 못했죠.","JPN":"だから自分を守る敵対者さえも、まともに作り出すことができませんでした。","ENG":"It hasn't even procured a proper Antagonist to protect itself.","TWN":"所以連保護自己的敵對者也製造不出來。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"이제 이 어린 세계는 끝을 마주보고 있습니다.","JPN":"今やこの幼い世界は終末に向かっています。","ENG":"This nascent world is already on the verge of extinction.","TWN":"現在這個年輕的世界正面臨到盡頭。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"전 누구도 지켜내지 못한 반쪽짜리 대적자일 뿐이지만……","JPN":"私は誰も守れなかった生半可な敵対者にすぎませんが……","ENG":"Although I'm just an incomplete Antagonist who has failed to protect anyone…","TWN":"雖然我只是個半吊子的敵對者……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"그래도 포기는 하지 않겠어요.","JPN":"だけど、諦めません。","ENG":"I refuse to give up.","TWN":"但我不會放棄！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"그게 제가 살아가는 방식이니까요.","JPN":"それが私の生き方ですから。","ENG":"Because… that is the way I choose to live.","TWN":"因為那是我的生存之道！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대체…… 어쩔 생각인가?","JPN":"いったい……どうするつもりだ？","ENG":"What… are you going to do, exactly?","TWN":"你到底……想做什麼？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"제 운명과 결합된 이 피를…… 다른 세계들에 넘길 겁니다.","JPN":"私の運命と結びついたこの血を……他の世界に託します。","ENG":"I'm going to pass this blood that's bonded with my fate… onto the other worlds.","TWN":"我要把和我的命運連結在一起的血……轉到其他世界。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"언젠가……. 후예들 중 누군가가……. 이 저주를 극복하고 제 힘을 이어받도록…….","JPN":"いつか……末裔の誰かが……この呪いを乗り越えて私の力を受け継ぐように……","ENG":"So one day… one of my descendants may… overcome this curse and inherit my powers…","TWN":"總有一天……我的後裔中，會有一個人……克服這個詛咒獲得我的力量……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"그래서 그들의 세계에도 닥쳐 올, 종말을 막을 수 있게……","JPN":"そして、彼らの世界に迫る終末を食い止められるように……","ENG":"So they may prevent the inevitable extinction of their own world…","TWN":"如此一來，就可以阻止他們的世界會面臨到的末日……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 후예들은? 자네 결정으로 괴로워할 그 사람들은?","JPN":"君の末裔たちは？　君の決定で苦しむあの人たちのことは？","ENG":"But what about your descendants? Will they not suffer because of your decision?","TWN":"你的後裔？你是說因為你的決定而受苦的人？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"……누군가는 짊어져야 할 업보입니다.","JPN":"……誰かが背負うべき因果です。","ENG":"…Someone's bound to carry on the legacy of this karma.","TWN":"……必須有人背起這個業障。"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"이걸로 하나의 세계라도, 단 하나의 세계라도……. 멸망의 굴레를 끊어낼 수 있다면…….","JPN":"これで一つの世界でも、たった一つの世界でも……滅亡のしがらみを断ち切ることができるのなら……","ENG":"If this can prevent the cycle of extinction… for even one world…","TWN":"只要這樣可以讓一個世界，就算只有一個世界也好……斷開滅亡的束縛……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 바보 같은……","JPN":"そんなバカな……","ENG":"How foolish…","TWN":"真是愚蠢的行為……"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 얼마나 걸릴지 생각해 본 적은 있나? 확률적으로 얼마나 희박한지는?","JPN":"それがどれほどかかるか、どれほど可能性が低いかは考えたのか？","ENG":"Have you ever thought about how long that could take? How statistically impossible that will be?","TWN":"你知道這要花多久的時間嗎？你有算過這個機率有多低嗎？"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"하지만 언젠가는 도달할 겁니다. 전 믿고 있어요.","JPN":"それでもいつかは到達するでしょう。私は信じています。","ENG":"But we'll get there one day. I have faith.","TWN":"我相信總有一天會發生的，我堅決相信！"},"stage":{"bg":"MAINSTREAM_7010012","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAVIOR_NPC_FAILED_NULL","text":{"KOREA":"반드시, 그렇게 될 거라고.","JPN":"必ず、そうなると。","ENG":"It must come to that. No matter what.","TWN":"一定會發生的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군. 결국 도달했군.","JPN":"……そうか。ついに到達したのか。","ENG":"I see... So we're finally here.","TWN":"……原來如此，就是現在嗎？"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"번뇌를 잊을 필요도, 태우거나, 초월할 필요도 없다.","JPN":"煩悩を忘れることも、焼却や超越する必要もない。","ENG":"There's no need to forget, scorch, or overcome Kleshas…","TWN":"不需要忘記、挪去或是超越煩惱，"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"삶이란……. 곧 번뇌이기 때문이다.","JPN":"人生とは……すなわち煩悩だからだ。","ENG":"For life itself… is Kleshas.","TWN":"因為人生……本來就是充滿煩惱。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"삶을 살아간다는 것은, 번뇌이자 또한 축복이기에.","JPN":"生きていくということは煩悩であり、そして祝福でもある。","ENG":"To live means to suffer Kleshas, but it is also a blessing.","TWN":"人活著就是會有煩惱，也會有幸福。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……늘 그렇듯 말은 쉬워도 깨우치기는 쉽지 않지.","JPN":"……いつものように言葉で言うのは簡単だが、悟ることは簡単ではない。","ENG":"As always… it's easier said than done.","TWN":"……這麼簡單的道理，我們卻常常想不明白。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 친구가 용혈을 가져간 것이 헛수고는 아니었군.","JPN":"あの友人の龍血を持っていったことは無駄ではなかった。","ENG":"I suppose my old friend didn't take the Dragon Blood in vain after all.","TWN":"原來他不是白忙一場，"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 이제 조금은 짐을 내려놓을 수 있겠어.","JPN":"私もこれで少しは肩の荷が下りたよ。","ENG":"I can finally make peace with myself a little more.","TWN":"現在我終於也可以稍微卸下重擔了。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……전 이제 어떻게 되죠?","JPN":"……僕はどうなるんですか？","ENG":"…So what's going to happen to me now?","TWN":"……那我現在該怎麼辦？"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"죽는 건가요?","JPN":"死ぬんですか？","ENG":"Am I going to die?","TWN":"去死嗎？"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜? 죽고 싶은가?","JPN":"それを聞く理由は？　死にたいのか？","ENG":"Why? Do you wish to die?","TWN":"為什麼？你想死嗎？"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 건 아니지만…… 조금은 미련이 남네요.","JPN":"そういうわけではありませんが……少し未練が残ってますね。","ENG":"Not really… I mean, there's one last thing I'd like to do.","TWN":"當然不想……我還有想完成的事。"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"고맙다는 말을 하고 싶어요. 스승님에게.","JPN":"感謝の言葉を伝えたいです、師匠に。","ENG":"I want to go say thank you. To my Master.","TWN":"我想和師父說聲謝謝。"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 가서 하게나.","JPN":"では、戻るがいい。","ENG":"Then do it.","TWN":"那就去吧。"},"stage":{"bg":"MAINSTREAM_7100010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"…What?","TWN":"……嗯？"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 용이 되기를 거부했어. 그러니 용혈의 힘은 더 이상 쓸 수 없겠지.","JPN":"君は龍になることを拒んだ。だから龍血の力はこれ以上使えない。","ENG":"You refused to become the Dragon. So you won't be able to use the power of the Dragon Blood any longer.","TWN":"你既然拒絕成為龍，就再也無法使用龍血的力量。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 대신 번뇌를 받아들이고 운명의 저주를 극복해냈어.","JPN":"しかしその代わりに煩悩を受け入れて、運命の呪いを乗り越えた。","ENG":"But instead, you accepted your Kleshas and overcame your cursed fate.","TWN":"但你選擇接受煩惱，並且克服了命運的詛咒，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 선조들이 남긴 생명과 힘은, 이제부터 그건 자네의 것일세.","JPN":"君の先祖たちが遺した生命と力は、これからは君のものだ。","ENG":"The life force and power your ancestors left behind is now yours.","TWN":"因此祖先留下的生命和力量現在是你的了。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"먼 과거로부터 순환의 뱀처럼 자네에게로 이어진 운명의 끈.","JPN":"遠い過去から循環の蛇のように君につながる運命の絆。","ENG":"That cord of fate that led to you from a past long gone, like the self-swallowing serpent.","TWN":"命運的繩索一旦找上你，命運的循環，"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 끈이 자네의 삶을 다시 한 번 이어 주겠지.","JPN":"その絆が君の人生をもう一度つないでくれるだろう。","ENG":"That cord will once again reconnect your life.","TWN":"會持續在你身上發生。"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7120010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아 참, 가기 전에 인사는 하고 가게나.","JPN":"ああ、戻る前に挨拶をしてから行ってくれ。","ENG":"Oh, you should say hello before you go.","TWN":"對了，在你離開前打聲招呼再走吧！"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 아주 오랫동안 기다려 온 분들이니까.","JPN":"君のことを長い間待っていた人たちだからな。","ENG":"They've been waiting for you for a very long time.","TWN":"有人等你很久了。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네……? 기다리다니, 누가…… 설마?","JPN":"はい……？　待っているって、誰が……まさか？","ENG":"Sorry…? Waiting for me? Who could have… oh, could it be?","TWN":"有人……？在等我？誰啊……難道是？"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"시윤아.","JPN":"シリュウ。","ENG":"Shiyoon.","TWN":"時雲～"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"우리 아들, 정말 많이 컸구나.","JPN":"私の息子、大きくなったね。","ENG":"Oh son, you're all grown up now.","TWN":"我的兒子，你長大了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아버지……? 어머니……?","JPN":"父さん……？　母さん……？","ENG":"Dad...? Mom…?","TWN":"爸爸……？媽媽……？"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"너한테 꼭…… 미안하다는 말을 하고 싶었단다.","JPN":"あなたには必ず……謝りたかったの。","ENG":"We really wanted to tell you… how sorry we are.","TWN":"媽媽……一直很想跟你說聲對不起，"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그리고…… 정말 보고 싶었다는 말도……","JPN":"そして……本当に会いたかった……","ENG":"And also… that we miss you dearly…","TWN":"還有……媽媽好想你……"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도……","JPN":"僕も……","ENG":"Me too…","TWN":"我也……"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 그랬어요…… 진심으로요.","JPN":"僕も同じです……心からそう思います。","ENG":"Me too… With all my heart.","TWN":"我也是……我也好想你們。"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"자, 여보. 그만 울고 웃으면서 보내 줍시다.","JPN":"さあ、泣くのはやめて笑顔で送ってあげよう。","ENG":"Come dear. Let us put our tears aside and send off our son with a smile.","TWN":"好了老婆，別再哭了，我們笑著送兒子離開吧。"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"아들아, 아무리 그립다고 해도 다 큰 자식이 부모 품에 안겨 있을 필요는 없는 법이다.","JPN":"シリュウ、お前はもう立派な一人前の男だ。\\nだから私たちの元を離れても逞しく生きていけると信じている。","ENG":"My son, I know you missed us, but a full grown man must leave the embrace of his parents one day.","TWN":"兒子，雖然爸爸媽媽很想你，但你已經是大人了，必須離開父母的懷抱了。"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그러니 여기엔…… 가급적이면 천천히 오거라.","JPN":"だからここには……できるだけ遅く、ゆっくり来なさい。","ENG":"So if at all possible… take your time coming back here.","TWN":"所以……你在另一個世界要好好活著，不要太快就來這裡找爸爸媽媽。"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"그리고 스승님께도 전해 주렴.","JPN":"そして師匠にも伝えてくれ。","ENG":"And also please tell the Master…","TWN":"幫我帶話給師父，"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"나와 연화, 둘 다 널 이렇게 잘 돌봐 줘서 감사하고 있다고.","JPN":"私とレンカ、二人ともお前のことを見守ってくれたことに感謝していると。","ENG":"How grateful Yeonhwa and I are for taking such great care of you.","TWN":"就說，我和蓮華很感謝她這麼照顧你。"},"stage":{"bg":"MAINSTREAM_7120011","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……네. 꼭 전할게요.","JPN":"……はい、必ず伝えます。","ENG":"…Yes. I'll be sure to tell her.","TWN":"……好，我會轉告師父的。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니 언젠가 제가 다시 올 때까지…… 잘 지내세요.","JPN":"だからいつか僕が戻ってくる時まで……お元気で。","ENG":"And I wish you the best… until I come back here someday.","TWN":"等我有一天在來到這裡之前……你們要好好保重。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"몸조심하렴. 밥 꼭 챙겨먹고.","JPN":"体に気をつけて、ご飯はちゃんと食べるのよ。","ENG":"Stay safe. And get three square meals a day.","TWN":"你要好好照顧身體，記得吃飯喔。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"우린 언제나…….","JPN":"私たちはいつだって……","ENG":"We'll always…","TWN":"爸爸媽媽……"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAD_NPC_YOON_NULL","text":{"KOREA":"네 편이란다.","JPN":"お前の味方だ。","ENG":"…be rooting for you, son.","TWN":"會永遠支持你。"},"stage":{"bg":"MAINSTREAM_7120012","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};